from outlines.prompts import prompt, register_filter, unregister_filter

register_filter('shout', lambda x: x.upper() + '!')

@prompt
def greet(name):
    '''Hello {{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')
try:
    greet('world')
    print('ERROR: should have raised')
except Exception as e:
    print('OK, unregistered:', type(e).__name__)

# precedence: global filter named 'name' should be overridden by built-in
register_filter('name', lambda x: 'SHOULD_NOT_APPEAR')
@prompt
def f(fn):
    '''{{ fn | name }}'''
def my_func(): pass
print(f(my_func))
unregister_filter('name')
"
"}

